{
   int stat = 0;

   OSRTSAFEPUTCHAR_ZTERM (pctxt, '{');
   rtJsonEncIncrIndent(pctxt);
   rtJsonEncIndent (pctxt);
   switch(pvalue->t) {
      case 1 : 
      {
         OSRTSAFEPUTCHAR_ZTERM (pctxt, '"');
         rtxCopyAsciiText (pctxt, "initiatingMessage");
         OSRTSAFEZTERM(pctxt);
         rtxCopyAsciiText (pctxt, "\":");
         OSRTSAFEZTERM(pctxt);
         stat = asn1JsonEnc_InitiatingMessage (pctxt, pvalue->u.initiatingMessage);
         if (stat != 0) {
            return LOG_RTERR (pctxt, stat);
         }
         break;
      }

      case 2 : 
      {
         OSRTSAFEPUTCHAR_ZTERM (pctxt, '"');
         rtxCopyAsciiText (pctxt, "successfulOutcome");
         OSRTSAFEZTERM(pctxt);
         rtxCopyAsciiText (pctxt, "\":");
         OSRTSAFEZTERM(pctxt);
         stat = asn1JsonEnc_SuccessfulOutcome (pctxt, pvalue->u.successfulOutcome);
         if (stat != 0) {
            return LOG_RTERR (pctxt, stat);
         }
         break;
      }

      case 3 : 
      {
         OSRTSAFEPUTCHAR_ZTERM (pctxt, '"');
         rtxCopyAsciiText (pctxt, "unsuccessfulOutcome");
         OSRTSAFEZTERM(pctxt);
         rtxCopyAsciiText (pctxt, "\":");
         OSRTSAFEZTERM(pctxt);
         stat = asn1JsonEnc_UnsuccessfulOutcome (pctxt, pvalue->u.unsuccessfulOutcome);
         if (stat != 0) {
            return LOG_RTERR (pctxt, stat);
         }
         break;
      }

      case 4 : 
      {
         /* encode choice extension */
         stat = rtJsonAsn1EncExtElem (pctxt, pvalue->u.extElem1);
         if (stat != 0) return LOG_RTERR (pctxt, stat);
         break;
      }

      default:  {
         return LOG_RTERR (pctxt, RTERR_INVOPT);
      }
   }
   rtJsonEncDecrIndent(pctxt);
   rtJsonEncIndent (pctxt);
   OSRTSAFEPUTCHAR_ZTERM (pctxt, '}');

   return stat;
}

